// src/pages/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { Box, Typography, Button, Grid, Card, CardContent, CircularProgress, Snackbar, Alert } from "@mui/material";
import axios from "axios";
import { useAuth } from "../contexts/AuthContext";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const { auth, logout } = useAuth();
  const navigate = useNavigate();
  const [riders, setRiders] = useState([]);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [snackbar, setSnackbar] = useState({ open: false, message: "", type: "success" });

  if (!auth || auth.role !== "admin") {
    navigate("/admin");
    return null;
  }

  // Fetch Users & Riders
  const fetchData = async () => {
    try {
      setLoading(true);
      const usersRes = await axios.get("/api/users");
      const ridersRes = await axios.get("/api/riders");
      setUsers(usersRes.data || []);
      setRiders(ridersRes.data || []);
    } catch (err) {
      console.error(err);
      setSnackbar({ open: true, message: "Failed to fetch data", type: "error" });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleApprove = async (id) => {
    try {
      await axios.post(`/api/rider/${id}/approve`);
      setSnackbar({ open: true, message: "Rider approved", type: "success" });
      fetchData();
    } catch (err) {
      console.error(err);
      setSnackbar({ open: true, message: "Error approving rider", type: "error" });
    }
  };

  const handleReject = async (id) => {
    try {
      await axios.post(`/api/rider/${id}/reject`);
      setSnackbar({ open: true, message: "Rider rejected", type: "warning" });
      fetchData();
    } catch (err) {
      console.error(err);
      setSnackbar({ open: true, message: "Error rejecting rider", type: "error" });
    }
  };

  const handleLogout = () => {
    logout();
    navigate("/admin");
  };

  return (
    <Box p={4}>
      <Typography variant="h4" gutterBottom>
        Rider App - Admin Dashboard
      </Typography>
      <Button onClick={handleLogout} sx={{ mb: 3 }} variant="contained" color="error">
        Logout
      </Button>

      {loading ? (
        <CircularProgress />
      ) : (
        <>
          <Typography variant="h6">Users ({users.length})</Typography>
          <Grid container spacing={2} sx={{ mb: 3 }}>
            {users.map((user) => (
              <Grid item xs={12} md={6} key={user._id}>
                <Card>
                  <CardContent>
                    <Typography>{user.fullName}</Typography>
                    <Typography>Email: {user.email}</Typography>
                    <Typography>Mobile: {user.mobile}</Typography>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>

          <Typography variant="h6">Riders ({riders.length})</Typography>
          <Grid container spacing={2}>
            {riders.map((rider) => (
              <Grid item xs={12} md={6} key={rider._id}>
                <Card>
                  <CardContent>
                    <Typography>{rider.fullName}</Typography>
                    <Typography>Email: {rider.email}</Typography>
                    <Typography>Mobile: {rider.mobile}</Typography>
                    <Typography>Status: {rider.approvalStatus || "pending"}</Typography>
                    <Box mt={1} display="flex" gap={1}>
                      <Button
                        variant="contained"
                        color="success"
                        onClick={() => handleApprove(rider._id)}
                        disabled={rider.approvalStatus === "approved"}
                      >
                        Approve
                      </Button>
                      <Button
                        variant="contained"
                        color="error"
                        onClick={() => handleReject(rider._id)}
                        disabled={rider.approvalStatus === "rejected"}
                      >
                        Reject
                      </Button>
                    </Box>
                  </CardContent>
                </Card>
              </Grid>
            ))}
          </Grid>
        </>
      )}

      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
      >
        <Alert severity={snackbar.type}>{snackbar.message}</Alert>
      </Snackbar>
    </Box>
  );
}
